# scripts/show_eval_diff.py
"""
Compare two eval run results and show which cases changed.
Use this after running the suite against a new prompt to review
changed cases before committing the new baseline.
"""
import argparse, json
from pathlib import Path

def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--old", type=Path, required=True)
    parser.add_argument("--new", type=Path, required=True)
    args = parser.parse_args()

    old_results = {r["id"]: r["result"] for r in json.loads(args.old.read_text()).get("results", [])}
    new_results = {r["id"]: r["result"] for r in json.loads(args.new.read_text()).get("results", [])}

    changed = [
        (cid, old_results[cid], new_results[cid])
        for cid in set(old_results) & set(new_results)
        if old_results[cid] != new_results[cid]
    ]
    new_cases = [cid for cid in new_results if cid not in old_results]
    dropped   = [cid for cid in old_results if cid not in new_results]

    print(f"Changed cases: {len(changed)}")
    for cid, old, new in sorted(changed):
        arrow = "✅ FAIL→PASS" if old == "FAIL" and new == "PASS" else "❌ PASS→FAIL"
        print(f"  {arrow}: {cid}")

    if new_cases:
        print(f"\nNew cases (no baseline): {len(new_cases)}")
        for cid in new_cases:
            print(f"  + {cid}: {new_results[cid]}")

    if dropped:
        print(f"\nDropped from new run: {len(dropped)}")
        for cid in dropped:
            print(f"  - {cid}")

if __name__ == "__main__":
    main()
